class Solution(object):
    def closestDivisors(self, num):
        def find_closest(n):
            for i in range(int(n**0.5), 0, -1):
                if n % i == 0:
                    return (i, n // i)
            return (1, n)
        res1 = find_closest(num + 1)
        res2 = find_closest(num + 2)
        if res1[1] - res1[0] < res2[1] - res2[0]:
            return res1
        return res2
